19452         match(I, m_LogicalOr(m_Value(), m_Value())))
19453       return RecurKind::Or;
19454     if (match(I, m_Xor(m_Value(), m_Value())))
19455       return RecurKind::Xor;
19456     if (match(I, m_FAdd(m_Value(), m_Value())))
19457       return RecurKind::FAdd;
19458     if (match(I, m_FMul(m_Value(), m_Value())))
19459       return RecurKind::FMul;
19460 
19461     if (match(I, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_Value())))
19462       return RecurKind::FMax;
19463     if (match(I, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_Value())))
19464       return RecurKind::FMin;
19465 
19466     if (match(I, m_Intrinsic<Intrinsic::maximum>(m_Value(), m_Value())))
19467       return RecurKind::FMaximum;
19468     if (match(I, m_Intrinsic<Intrinsic::minimum>(m_Value(), m_Value())))
19469       return RecurKind::FMinimum;
