19471     // either form.
19472     // TODO: If we are canonicalizing to intrinsics, we can remove several
19473     //       special-case paths that deal with selects.
19474     if (match(I, m_SMax(m_Value(), m_Value())))
19475       return RecurKind::SMax;
19476     if (match(I, m_SMin(m_Value(), m_Value())))
19477       return RecurKind::SMin;
19478     if (match(I, m_UMax(m_Value(), m_Value())))
19479       return RecurKind::UMax;
19480     if (match(I, m_UMin(m_Value(), m_Value())))
19481       return RecurKind::UMin;
