19483     if (auto *Select = dyn_cast<SelectInst>(I)) {
19484       // Try harder: look for min/max pattern based on instructions producing
19485       // same values such as: select ((cmp Inst1, Inst2), Inst1, Inst2).
19486       // During the intermediate stages of SLP, it's very common to have
19487       // pattern like this (since optimizeGatherSequence is run only once
19488       // at the end):
19489       // %1 = extractelement <2 x i32> %a, i32 0
19490       // %2 = extractelement <2 x i32> %a, i32 1
19491       // %cond = icmp sgt i32 %1, %2
19492       // %3 = extractelement <2 x i32> %a, i32 0
19493       // %4 = extractelement <2 x i32> %a, i32 1
19494       // %select = select i1 %cond, i32 %3, i32 %4
19495       CmpPredicate Pred;
19496       Instruction *L1;
19497       Instruction *L2;
19498 
19499       Value *LHS = Select->getTrueValue();
19500       Value *RHS = Select->getFalseValue();
19501       Value *Cond = Select->getCondition();
