19504       if (match(Cond, m_Cmp(Pred, m_Specific(LHS), m_Instruction(L2)))) {
19505         if (!isa<ExtractElementInst>(RHS) ||
19506             !L2->isIdenticalTo(cast<Instruction>(RHS)))
