19509         if (!isa<ExtractElementInst>(LHS) ||
19510             !L1->isIdenticalTo(cast<Instruction>(LHS)))
19511           return RecurKind::None;
19512       } else {
19513         if (!isa<ExtractElementInst>(LHS) || !isa<ExtractElementInst>(RHS))
19514           return RecurKind::None;
19515         if (!match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Instruction(L2))) ||
19516             !L1->isIdenticalTo(cast<Instruction>(LHS)) ||
19517             !L2->isIdenticalTo(cast<Instruction>(RHS)))
