19519       }
19520 
19521       switch (Pred) {
19522       default:
19523         return RecurKind::None;
19524       case CmpInst::ICMP_SGT:
19525       case CmpInst::ICMP_SGE:
19526         return RecurKind::SMax;
19527       case CmpInst::ICMP_SLT:
19528       case CmpInst::ICMP_SLE:
19529         return RecurKind::SMin;
19530       case CmpInst::ICMP_UGT:
19531       case CmpInst::ICMP_UGE:
19532         return RecurKind::UMax;
19533       case CmpInst::ICMP_ULT:
19534       case CmpInst::ICMP_ULE:
19535         return RecurKind::UMin;
